CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TYPE profile_type AS ENUM ('PERSON','STORE');
CREATE TYPE item_owner_type AS ENUM ('WARDROBE','STORE');
CREATE TABLE users (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL, profile_type profile_type NOT NULL, avatar_url TEXT, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE stores (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_user_id UUID UNIQUE REFERENCES users(id) ON DELETE CASCADE, store_name TEXT NOT NULL, cnpj TEXT, description TEXT, banner_url TEXT, logo_url TEXT, social_links JSONB DEFAULT '{}', created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE follows (follower_user_id UUID REFERENCES users(id) ON DELETE CASCADE, followed_user_id UUID REFERENCES users(id) ON DELETE CASCADE, store_id UUID REFERENCES stores(id) ON DELETE CASCADE, created_at TIMESTAMPTZ DEFAULT now(), CHECK ((followed_user_id IS NULL) <> (store_id IS NULL)) );
CREATE UNIQUE INDEX uniq_follow_user ON follows(follower_user_id, followed_user_id) WHERE followed_user_id IS NOT NULL;
CREATE UNIQUE INDEX uniq_follow_store ON follows(follower_user_id, store_id) WHERE store_id IS NOT NULL;
CREATE TABLE items (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), owner_user_id UUID REFERENCES users(id) ON DELETE CASCADE, store_id UUID REFERENCES stores(id) ON DELETE CASCADE, owner_type item_owner_type NOT NULL, source_store_id UUID REFERENCES stores(id), source_item_id UUID REFERENCES items(id), name TEXT NOT NULL, category TEXT NOT NULL, color TEXT, sizes TEXT[] DEFAULT '{}', price NUMERIC(10,2), purchase_link TEXT, image_urls TEXT[] DEFAULT '{}', metadata JSONB DEFAULT '{}', created_at TIMESTAMPTZ DEFAULT now(), CHECK ((owner_type='WARDROBE' AND owner_user_id IS NOT NULL) OR (owner_type='STORE' AND store_id IS NOT NULL)));
CREATE TABLE looks (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES users(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, item_ids UUID[] DEFAULT '{}', image_url TEXT, is_public BOOLEAN DEFAULT true, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE showcases (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), store_id UUID REFERENCES stores(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT, cover_url TEXT, item_ids UUID[] DEFAULT '{}', starts_at TIMESTAMPTZ, ends_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT now());
CREATE TABLE item_saves (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID REFERENCES users(id) ON DELETE CASCADE, store_id UUID REFERENCES stores(id) ON DELETE CASCADE, source_item_id UUID REFERENCES items(id) ON DELETE CASCADE, copied_item_id UUID REFERENCES items(id) ON DELETE SET NULL, created_at TIMESTAMPTZ DEFAULT now(), UNIQUE(user_id, source_item_id));
CREATE TABLE showcase_comments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), showcase_id UUID REFERENCES showcases(id) ON DELETE CASCADE, user_id UUID REFERENCES users(id) ON DELETE CASCADE, rating INT CHECK (rating BETWEEN 1 AND 5), comment TEXT, created_at TIMESTAMPTZ DEFAULT now());
CREATE INDEX idx_items_store ON items(store_id, created_at DESC); CREATE INDEX idx_items_user ON items(owner_user_id, created_at DESC); CREATE INDEX idx_follows_user ON follows(follower_user_id); CREATE INDEX idx_looks_feed ON looks(user_id, created_at DESC) WHERE is_public;
